jQuery(document).ready(function($){function trainigSlider(){if($(".training-slider").length){$(".training-slider").slick({slidesToShow:2.5,slidesToScroll:1,dots:!1,arrows:!0,infinite:!1,autoplay:!1,responsive:[{breakpoint:1200,settings:{slidesToShow:2,slidesToScroll:1,dots:!0,arrows:!1,}},{breakpoint:992,settings:{slidesToShow:1.5,slidesToScroll:1,dots:!0,arrows:!1,autoplay:!1,}},{breakpoint:490,settings:{slidesToShow:1,slidesToScroll:1,dots:!0,arrows:!1,autoplay:!1,}}]})}}
$(document).on("click",".tab-btn",function(){if($('.training-slider').hasClass('slick-initialized')){$('.training-slider').slick('unslick')}
trainigSlider()})});function initReadMoreButtons(){const wrappers=document.querySelectorAll(".webinar-title-wrapper");wrappers.forEach(wrapper=>{const title=wrapper.querySelector(".webinar-title");const button=wrapper.querySelector(".toggle-btn");wrapper.classList.remove("expanded");setTimeout(()=>{const isOverflowing=title.scrollHeight>title.clientHeight;if(!isOverflowing){button.style.display="none"}else{button.style.display="inline";button.addEventListener("click",function(){const isExpanding=!wrapper.classList.contains("expanded");wrappers.forEach(otherWrapper=>{if(otherWrapper!==wrapper){otherWrapper.classList.remove("expanded");const otherButton=otherWrapper.querySelector(".toggle-btn");if(otherButton){otherButton.textContent="Read More"}}});wrapper.classList.toggle("expanded");this.textContent=wrapper.classList.contains("expanded")?"Read Less":"Read More"})}},100)})}
document.addEventListener("DOMContentLoaded",initReadMoreButtons);window.addEventListener("resize",initReadMoreButtons);document.addEventListener("DOMContentLoaded",function(){const readMoreBtns=document.querySelectorAll(".show-popup");const overlay=document.getElementById("overlay");const popup=document.getElementById("recruiter_readMore_popup");const popup2=document.getElementById("recruiter2_readMore_popup");const closeBtn=document.getElementById("closePopup");readMoreBtns.forEach(function(btn){btn.addEventListener("click",function(){popup.classList.remove("hidden");popup2.classList.remove("hidden");overlay.classList.add("active")})});closeBtn.addEventListener("click",function(){popup.classList.add("hidden");popup2.classList.add("hidden");overlay.classList.remove("active")});overlay.addEventListener("click",function(){popup.classList.add("hidden");popup2.classList.add("hidden");overlay.classList.remove("active")})})